// Passthrough: this node does not modify pixel data.
// Semantic overrides are collected by the evaluator and applied
// to downstream node parameters via context.SemanticOverrides.
if (inputs.Length > 0 && inputs[0] != null)
    return inputs[0]!;

var size = context.GetEffectiveSize();
return new PixelBuffer(size, size);
